class Solution:
    def maxStrength(self, nums) -> int:
        from itertools import combinations
        n = len(nums)
        best = None
        for size in range(1, n + 1):
            for combo in combinations(nums, size):
                p = 1
                for x in combo:
                    p *= x
                if best is None or p > best:
                    best = p
        return best

