class Solution:
    def maxStrength(self, nums) -> int:
        n = len(nums)
        best = None
        for mask in range(1, 1 << n):
            product = 1
            for i in range(n):
                if mask & (1 << i):
                    product *= nums[i]
            if best is None or product > best:
                best = product
        return best

