var maxStrength = function(nums) {
    const n = nums.length;
    let best = null;
    for (let mask = 1; mask < (1 << n); mask++) {
        let product = 1;
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) product *= nums[i];
        }
        if (best === null || product > best) best = product;
    }
    return best;
};
